import React from 'react'
import AllCompo from '../components/AllCompo';
import Footer from '../components/Footer';
import HeaderContact from './HeaderContact';
import ContactPage from './ContactPage';
function AllContact() {
  return (
    <div>
        <AllCompo/>
        <HeaderContact/>
        <ContactPage/>
        <Footer/>
    </div>
  )
}

export default AllContact ;
